INSERT INTO prescription_examples (student_key, student_profile, workouts, workout_split) VALUES ('rebeca_sauwen', '{"name":"Rebeca Sauwen","mapped_name":null,"birth_date":"1995-06-15","profession":"Cantora, produtora executiva, freelancer de marketing digital musical.","sports_history":"Infância: natação, ballet, sapateado, capoeira.\nAdolescência: uma época mais sedentária, entrei em algumas academias, mas nada frequente. \n18 a 24 - Comecei a fazer trilhas e andar de bicicleta pela cidade. Nada constante, mas definitivamente mais intenso. Ia a praia de bicicleta, 13km de ida e 13km de volta. Aos 21, fiz uns 3 meses de academia na BodyTech e consegui ver resultado, mas meu treino era muito intenso e demorava 2h. Perto dos 23, fiz Yoga e entrava e saía de academia. \n25 - Exercícios funcionais em casa, aplicativos + bicicleta para me locomover. (2020) \n26 - Canoa polinésia por 4 meses em Niterói + bicicleta para me locomover. \n27 -  Morei em São Paulo, entrei na academia, fiz aula de funcional + jump e às vezes musculação. \n28 - De volta ao Rio, fiz aulas de canoa polinésia de Novembro a Março e saí quando chegou o inverno. Nessa época entrei na Yoga Vinyasa e fiz o ano inteiro com frequência. \n29 - Yoga + bicicleta ergométrica que comprei para casa. Desde o último Novembro, faço musculação na academia e 1h na minha bicicleta em casa. Parei a yoga durante 2 meses, mas voltarei em Abril.  \n\nO que não gosto: Burpee, Circuitos, Afundo, Escada. \nO que gosto: Bicicleta, Yoga, Elíptico. Musculação: tenho começado a gostar de treinar a parte superior. Prefiro fazer exercícios em aparelhos, mas alguns com halter. Desde que tive condromalácia, comecei a ter mais receio de treinar perna. Gosto de correr, mas meu joelho acaba doendo.","injuries":["Tenho condromalácia patelar nos dois joelhos."],"health_conditions":["Costumo ter amigdalite com frequência."],"medications":["Não. Apenas vitamina D."],"current_practice":"A partir dos 18 anos comecei a ser mais ativa. Mas em questão de constância, 4/5 anos. Principalmente, exercícios aeróbicos.","goal":"Quero emagrecer. Desde os 27 acho que meu metabolismo desacelerou. Minha alimentação, entretanto, é super saudável, faço acompanhamento com nutri e costumo me manter ativa com exercícios aeróbicos principalmente. Quero emagrecer de forma saudável e acredito que focar no crescimento de massa magra faça parte dessa equação.","weekly_frequency":4,"session_duration":"1h a 1h40","gender":"F","experience_level":"intermediário","form_timestamp":"2025/03/23 8:30:35 PM GMT-3"}'::jsonb, '{"A":{"focus":"","exercises":[{"name":"Puxada Frente Pegada Pronada","method":"Tradicional","series_data":{"rep":"2025-08-06 00:00:00","peso":"35.0","intervalo":"45\"","obs":"Pegada pronada é quando a palma das mãos está para frente, o afastamento deve ser na largura dos seus ombros."}},{"name":"Agachamento Cálice com Halter","method":"Tradicional","series_data":{"rep":"2023-12-08 00:00:00","peso":"1 Halter de 14-18kg","intervalo":"1''30\" - 2''","obs":"Realizar a \"pegada\" com o halter na vertical, usando a palma das mãos formando um cálice com as mãos e os antebraços, o halter fica a frente do seu tronco, na altura do seu peito/ombros."}},{"name":"Desenvolvimento de Ombros na Máquina","method":"Tradicional","series_data":{"rep":"2025-10-08 00:00:00","peso":"10.0","intervalo":"1''30\" - 2''"}},{"name":"Cadeira Extensora","method":"Tradicional","series_data":{"rep":"2025-12-10 00:00:00","peso":"25.0","intervalo":"1''30\"","obs":"Tentar trabalhar de forma dinâmica todas as repetições, achar uma carga que não gere dor e pode progredir o peso entre as séries."}},{"name":"Remada Serrote com Halter","method":"Tradicional","series_data":{"rep":"10 / 10","peso":"Halter de aprox. 12kg","intervalo":"1''","obs":"Apoiar uma mão e um joelho em um banco reto, com a outra mão segurar 1 halter e realizar o movimento de remada na vertical, trazendo o halter ao lado das suas costelas. Fazer 10 reps em cada lado"}},{"name":"Cadeira Abdutora","method":"Tradicional","series_data":{"rep":"10-14","peso":"50.0","intervalo":"1''"}}]},"Casa":{"focus":"","exercises":[{"name":"Agachamento c Halteres + Desenvolvimento de Ombros c/ Halteres","method":"Bi-Set","series_data":{"rep":"12 + 10","peso":"Halter 4kg","intervalo":"1''","obs":"X"}},{"name":"Abodminal Remada + Prancha Alta Passando o Halter","method":"Bi-Set","series_data":{"rep":"15 + 30","peso":"Halter 4kg","intervalo":"1''30\""}},{"name":"Elevaçao Frontal Halteres + Avanços Alternados","method":"Bi-Set","series_data":{"rep":"10 + 20","peso":"Halter 4kg","intervalo":"1''30\"","obs":"Para os avanços alternados, você não precisa usar os halteres, somente o peso do corpo."}},{"name":"Abdominal Curto com 1 Halter + Toque nos Ombros alternados","method":"Bi-Set","series_data":{"rep":"10 + 20","intervalo":"1''30\""}}]},"C":{"focus":"","exercises":[{"name":"[Unknown]","method":"Pré-Exaustão","series_data":{"rep":"8+10","peso":"Halteres de 4/5kg para elevação frontal | FIZ 4kg + 10kg","intervalo":"1''30","obs":"Realizar a elevação frontal e logo em seguida fazer o desenvolvimento de ombros na máquina, só então, fazer o intervalo de 1''30\""}},{"name":"[Unknown]","method":"Tradicional","series_data":{"rep":"12.0","peso":"4kg em cada | FIZ 4kg","intervalo":"2''","obs":"X"}},{"name":"[Unknown]","method":"Tradicional","series_data":{"rep":"15.0","peso":"Aprox 40kg (a depender do tipo de máquina) | FIZ 45kg","intervalo":"1''30\"","obs":"Ache a carga que fique desafiador fazer as 15reps"}},{"name":"[Unknown]","method":"Tradicional","series_data":{"rep":"12.0","peso":"Corporal | ok","intervalo":"1''"}}]},"D":{"focus":"","exercises":[{"name":"[Unknown]","method":"Tradicional","series_data":{"rep":"2023-12-08 00:00:00","peso":"Aprox. 98-108kg","intervalo":"2''"}},{"name":"[Unknown]","method":"Tradicional","series_data":{"rep":"2023-12-08 00:00:00","intervalo":"1''30\""}},{"name":"[Unknown]","method":"Tradicional","series_data":{"rep":"2023-12-08 00:00:00","intervalo":"1''","obs":"X"}},{"name":"[Unknown]","method":"DropSet","series_data":{"rep":"10+10","intervalo":"1''30\"","obs":"X"}},{"name":"[Unknown]","method":"Tradicional","series_data":{"rep":"10-14","intervalo":"1''30\"","obs":"X"}}]}}'::jsonb, ARRAY['A','Casa','C','D']::TEXT[]) ON CONFLICT (student_key) DO UPDATE SET student_profile = EXCLUDED.student_profile, workouts = EXCLUDED.workouts, workout_split = EXCLUDED.workout_split;